commands_run:
cat > .tmp-vitest-ai-timeline-agent.config.ts <<'EOF'
import { defineConfig } from 'vitest/config';
import path from 'node:path';
import { createEdgeVitestTestConfig } from './config/testing/vitest.edge.shared';
import { buildEdgeAliasMap } from './config/testing/vitest.edge.aliases';

const projectRoot = '/Users/peteromalley/Documents/reigh-workspace/reigh-app';
const mocksDir = path.resolve(projectRoot, 'supabase/functions/_tests/mocks');
const stripeSpecifier = 'https:' + '//esm.sh/stripe@14.21.0';
const groqSpecifier = 'npm' + ':groq-sdk@0.26.0';

export default defineConfig({
  resolve: {
    alias: {
      '@': path.resolve(projectRoot, 'src'),
      ...buildEdgeAliasMap(mocksDir),
      [stripeSpecifier]: path.resolve(mocksDir, 'stripe.ts'),
      [groqSpecifier]: path.resolve(mocksDir, 'groqSdk.ts'),
    },
  },
  test: createEdgeVitestTestConfig({
    include: ['supabase/functions/ai-timeline-agent/**/*.test.ts'],
    exclude: ['supabase/functions/**/node_modules/**'],
  }),
});
EOF
npx vitest run --config .tmp-vitest-ai-timeline-agent.config.ts
exit_code=$?
rm -f .tmp-vitest-ai-timeline-agent.config.ts
exit $exit_code

